import{c as i,S as h,j as o,m as a}from"./chunks/framework.8aa1YH_s.js";const k=JSON.parse('{"title":"Quản lý Giáo viên","description":"","frontmatter":{},"headers":[],"relativePath":"admin/quan-ly-giao-vien.md","filePath":"admin/quan-ly-giao-vien.md","lastUpdated":0}'),t={name:"admin/quan-ly-giao-vien.md"};function g(c,n,l,r,e,s){return h(),o("div",null,[...n[0]||(n[0]=[a('<h1 id="quan-ly-giao-vien" tabindex="-1">Quản lý Giáo viên <a class="header-anchor" href="#quan-ly-giao-vien" aria-label="Permalink to “Quản lý Giáo viên”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/account/teacher</code></p><p>Nơi tạo và quản lý tài khoản giáo viên. Khác với học viên, <strong>giáo viên không tự đăng ký</strong> - tài khoản phải do Admin tạo.</p><h2 id="danh-sach-giao-vien" tabindex="-1">Danh sách giáo viên <a class="header-anchor" href="#danh-sach-giao-vien" aria-label="Permalink to “Danh sách giáo viên”">​</a></h2><p>Cột thông tin:</p><ul><li>Họ và tên, Ảnh đại diện</li><li>Số điện thoại, Email</li><li><strong>Môn / Chuyên môn</strong> dạy</li><li><strong>Số khóa đang phụ trách</strong></li><li><strong>Số học viên</strong> đang dạy</li><li>Ngày tạo tài khoản</li><li>Trạng thái (Hoạt động / Tạm khóa)</li><li>Thao tác</li></ul><h2 id="tao-tai-khoan-giao-vien" tabindex="-1">Tạo tài khoản giáo viên <a class="header-anchor" href="#tao-tai-khoan-giao-vien" aria-label="Permalink to “Tạo tài khoản giáo viên”">​</a></h2><ol><li>Bấm <strong>Thêm giáo viên</strong>.</li><li>Điền: <ul><li><strong>Họ và tên</strong> (sẽ hiển thị công khai cho học viên)</li><li><strong>Số điện thoại</strong>, <strong>Email</strong> - giáo viên dùng để đăng nhập</li><li><strong>Mật khẩu mặc định</strong> (yêu cầu đổi khi đăng nhập lần đầu)</li><li><strong>Môn dạy / Chuyên môn</strong> (Toán, Văn, Lý, Hóa, ...)</li><li><strong>Bằng cấp / Học vị</strong> (Cử nhân, Thạc sĩ, ...)</li><li><strong>Giới thiệu ngắn</strong> (bio hiển thị trên trang khóa học)</li><li><strong>Ảnh đại diện</strong></li></ul></li><li>(Tùy chọn) Chọn <strong>Đại lý / Chiết khấu</strong> nếu giáo viên là cộng tác bên ngoài.</li><li>Bấm <strong>Lưu</strong>. Hệ thống gửi tài khoản qua email/SMS cho giáo viên.</li></ol><h2 id="sua-ho-so-giao-vien" tabindex="-1">Sửa hồ sơ giáo viên <a class="header-anchor" href="#sua-ho-so-giao-vien" aria-label="Permalink to “Sửa hồ sơ giáo viên”">​</a></h2><ul><li>Bấm icon <strong>Sửa</strong>.</li><li>Có thể chỉnh tất cả các trường ngoại trừ <strong>ID hệ thống</strong>.</li><li>Nếu đổi số điện thoại / email → thông báo lại cho giáo viên.</li></ul><h2 id="phan-cong-khoa-hoc" tabindex="-1">Phân công khóa học <a class="header-anchor" href="#phan-cong-khoa-hoc" aria-label="Permalink to “Phân công khóa học”">​</a></h2><p>Có 2 cách:</p><ol><li><strong>Vào chi tiết khóa học</strong> (Đào tạo → Khóa học) → chọn giáo viên phụ trách ở phần thông tin.</li><li><strong>Vào chi tiết giáo viên</strong> → tab <strong>Khóa học</strong> → bấm <strong>Gán khóa</strong>.</li></ol><blockquote><p>Mỗi khóa học có 1 giáo viên chính. Có thể có thêm trợ giảng nếu hệ thống cho phép.</p></blockquote><h2 id="tam-khoa-mo-khoa" tabindex="-1">Tạm khóa / Mở khóa <a class="header-anchor" href="#tam-khoa-mo-khoa" aria-label="Permalink to “Tạm khóa / Mở khóa”">​</a></h2><ul><li>Khi giáo viên nghỉ tạm thời, vi phạm, hoặc chấm dứt hợp tác → bấm <strong>Khóa</strong>.</li><li>Sau khi khóa: giáo viên <strong>không đăng nhập được</strong>; các khóa học vẫn còn nhưng nên reassign cho người khác.</li></ul><h2 id="xoa-tai-khoan-giao-vien" tabindex="-1">Xóa tài khoản giáo viên <a class="header-anchor" href="#xoa-tai-khoan-giao-vien" aria-label="Permalink to “Xóa tài khoản giáo viên”">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Cảnh báo</p><p>Trước khi xóa, cần <strong>chuyển giao toàn bộ khóa học và bài giảng</strong> sang giáo viên khác. Nếu không, các khóa đó sẽ rơi vào trạng thái &quot;không có người phụ trách&quot;.</p></div><h2 id="chiet-khau-cho-giao-vien" tabindex="-1">Chiết khấu cho giáo viên <a class="header-anchor" href="#chiet-khau-cho-giao-vien" aria-label="Permalink to “Chiết khấu cho giáo viên”">​</a></h2><p>Nếu giáo viên là cộng tác viên (không phải nhân viên cơ hữu), bạn có thể cấu hình tỷ lệ ăn chia:</p><ol><li>Vào <strong><a href="./dai-ly">Đại lý</a></strong> → tạo tài khoản đại lý/giáo viên.</li><li>Liên kết tài khoản giáo viên với cấu hình đại lý.</li><li>Hệ thống tự tính chiết khấu mỗi khi có hóa đơn liên quan tới khóa của giáo viên đó.</li><li>Xem báo cáo tại <strong><a href="./chiet-khau">Chiết khấu</a></strong>.</li></ol><h2 id="xem-hieu-qua-giang-day" tabindex="-1">Xem hiệu quả giảng dạy <a class="header-anchor" href="#xem-hieu-qua-giang-day" aria-label="Permalink to “Xem hiệu quả giảng dạy”">​</a></h2><ul><li>Vào <strong><a href="./thong-ke#_2-thong-ke-giao-vien">Thống kê → Giáo viên</a></strong>.</li><li>Hoặc trong chi tiết giáo viên có tab <strong>Hiệu quả</strong>: số học viên, doanh thu, đánh giá trung bình.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Giáo viên quên mật khẩu, không đăng nhập được.</strong> → Vào chi tiết → bấm <strong>Reset mật khẩu</strong>, gửi mật khẩu mới cho giáo viên.</p><p><strong>Giáo viên muốn đổi ảnh / bio.</strong> → Họ có thể tự đổi ở <code>https://lamsonedutech.vn/teacher/profile</code>. Admin chỉ can thiệp khi cần.</p><p><strong>Cần cấp quyền giáo viên xem được điểm thi của TẤT CẢ học viên (không chỉ học viên của họ).</strong> → Tạo cho họ một <strong>chức vụ nhân viên</strong> thay vì giáo viên, hoặc cấp quyền <code>student</code> trong Phân quyền.</p>',27)])])}const v=i(t,[["render",g]]);export{k as __pageData,v as default};
